ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name ?certificate ?title WHERE {
  ?journalists a :Journalists .
  ?articles a :Articles .
  ?articles p:hasjournalists ?journalists .
  ?journalists p:name ?name .
  ?journalists p:Certificate ?certificate .
  ?articles p:title ?title .
} }
  component_2: { SELECT ?name ?degree ?title WHERE {
  ?journalists a :Journalists .
  ?articles a :Articles .
  ?articles p:hasjournalists ?journalists .
  ?journalists p:name ?name .
  ?journalists p:Degree ?degree .
  ?articles p:title ?title .
} }
  full: { SELECT ?name ?degree ?certificate ?title WHERE {
  ?journalists a :Journalists .
  ?articles a :Articles .
  ?articles p:hasjournalists ?journalists .
  ?journalists p:name ?name .
  ?journalists p:Degree ?degree .
  ?journalists p:Certificate ?certificate .
  ?articles p:title ?title .
} }
}

